import json
import pymysql
import os

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    
    connection = None
    
    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            cursorclass=pymysql.cursors.DictCursor,
            connect_timeout=5
        )
        
        query_params = event.get('queryStringParameters', {}) or {}
        body_params = {}
        
        if event.get('body'):
            try:
                body_params = json.loads(event['body'])
            except:
                pass
        
        search_params = {**query_params, **body_params}
        
        query, params = build_search_query(search_params)
        
        with connection.cursor() as cursor:
            cursor.execute(query, params)
            results = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': True,
                'count': len(results),
                'data': results
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': False,
                'error': str(e)
            })
        }
        
    finally:
        if connection:
            connection.close()


def build_search_query(search_params):
    base_query = "SELECT * FROM products WHERE 1=1"
    conditions = []
    params = []
    
    if 'name' in search_params and search_params['name']:
        conditions.append("name LIKE %s")
        params.append(f"%{search_params['name']}%")
    
    if 'category' in search_params and search_params['category']:
        conditions.append("category = %s")
        params.append(search_params['category'])
    
    if 'min_price' in search_params and search_params['min_price']:
        conditions.append("price >= %s")
        params.append(float(search_params['min_price']))
    
    if 'max_price' in search_params and search_params['max_price']:
        conditions.append("price <= %s")
        params.append(float(search_params['max_price']))
    
    if 'brand' in search_params and search_params['brand']:
        conditions.append("brand = %s")
        params.append(search_params['brand'])
    
    if 'in_stock' in search_params and search_params['in_stock']:
        in_stock_value = search_params['in_stock'].lower() in ['true', '1', 'yes']
        if in_stock_value:
            conditions.append("stock_quantity > 0")
    
    if 'sku' in search_params and search_params['sku']:
        conditions.append("sku = %s")
        params.append(search_params['sku'])
    
    if 'description' in search_params and search_params['description']:
        conditions.append("description LIKE %s")
        params.append(f"%{search_params['description']}%")
    
    if 'tags' in search_params and search_params['tags']:
        conditions.append("tags LIKE %s")
        params.append(f"%{search_params['tags']}%")
    
    if 'status' in search_params and search_params['status']:
        conditions.append("status = %s")
        params.append(search_params['status'])
    
    if 'created_after' in search_params and search_params['created_after']:
        conditions.append("created_at >= %s")
        params.append(search_params['created_after'])
    
    if 'created_before' in search_params and search_params['created_before']:
        conditions.append("created_at <= %s")
        params.append(search_params['created_before'])
    
    if 'rating_min' in search_params and search_params['rating_min']:
        conditions.append("rating >= %s")
        params.append(float(search_params['rating_min']))
    
    if 'rating_max' in search_params and search_params['rating_max']:
        conditions.append("rating <= %s")
        params.append(float(search_params['rating_max']))
    
    for condition in conditions:
        base_query += f" AND {condition}"
    
    order_by = search_params.get('order_by', 'id')
    valid_order_fields = ['id', 'name', 'price', 'created_at', 'rating', 'stock_quantity']
    if order_by not in valid_order_fields:
        order_by = 'id'
    
    order_direction = search_params.get('order_direction', 'ASC').upper()
    if order_direction not in ['ASC', 'DESC']:
        order_direction = 'ASC'
    
    base_query += f" ORDER BY {order_by} {order_direction}"
    
    limit = int(search_params.get('limit', 100))
    if limit > 1000:
        limit = 1000
    base_query += f" LIMIT {limit}"
    
    offset = int(search_params.get('offset', 0))
    if offset > 0:
        base_query += f" OFFSET {offset}"
    
    return base_query, params